# Allowed header prefixes that can be forwarded
ALLOWED_HEADER_PREFIXES = (
    "x-request-",
    "x-correlation-",
    "x-trace-",
    "x-user-",
    "x-session-",
    "x-client-",
    "authorization",
    "accept-language",
    "user-agent",
)

# Headers that must NEVER be forwarded
BLOCKED_HEADERS = frozenset({
    "x-internal-secret",
    "x-admin-override",
    "grpc-timeout",
    "grpc-encoding",
    "grpc-accept-encoding",
    "grpc-status",
    "grpc-message",
    "grpc-status-details-bin",
    "te",
    "host",
    "content-type",
    "content-length",
    "connection",
    "transfer-encoding",
})

# Pattern for valid metadata key: lowercase alphanumeric, hyphens, underscores
# Must not contain newlines, colons, or other injection characters
VALID_KEY_PATTERN = re.compile(r'^[a-z][a-z0-9_\-]{0,63}$')

# Binary metadata keys must end with "-bin"
BINARY_KEY_SUFFIX = "-bin"

# Pattern to detect injection attempts in values
# Disallow carriage returns, newlines, and null bytes which could be used for injection
INJECTION_PATTERN = re.compile(r'[\r\n\x00]')

# Maximum metadata value length
MAX_VALUE_LENGTH = 8192

# Maximum number of metadata entries
MAX_METADATA_ENTRIES = 50


class MetadataValidationError(Exception):
    """Raised when metadata validation fails."""
    pass


def sanitize_metadata_key(key: str) -> Optional[str]:
    """
    Sanitize and validate a metadata key.
    
    gRPC metadata keys must be:
    - Lowercase ASCII letters, digits, hyphens, underscores
    - Must start with a letter
    - Must not match blocked headers
    - Must not start with 'grpc-' (reserved by gRPC)
    
    Returns sanitized key or None if invalid.
    """
    if not isinstance(key, str):
        return None
    
    # Normalize to lowercase and strip whitespace
    key = key.lower().strip()
    
    # Check against blocked headers
    if key in BLOCKED_HEADERS:
        return None
    
    # Block gRPC reserved prefix
    if key.startswith("grpc-"):
        return None
    
    # Validate key format
    if not VALID_KEY_PATTERN.match(key):
        return None
    
    return key


def sanitize_metadata_value(value: str, key: str) -> Optional[str]:
    """
    Sanitize and validate a metadata value.
    
    Prevents injection by:
    - Removing/rejecting values with newlines, carriage returns, null bytes
    - Enforcing maximum length
    - Ensuring proper encoding
    
    Returns sanitized value or None if invalid.
    """
    if not isinstance(value, (str, bytes)):
        return None
    
    if isinstance(value, bytes):
        # Binary values are only allowed for -bin keys
        if not key.endswith(BINARY_KEY_SUFFIX):
            try:
                value = value.decode('utf-8')
            except UnicodeDecodeError:
                return None
        else:
            # For binary keys, return as-is after length check
            if len(value) > MAX_VALUE_LENGTH:
                return None
            return value
    
    # Check for injection patterns (CRLF injection, null bytes)
    if INJECTION_PATTERN.search(value):
        return None
    
    # Enforce maximum length
    if len(value) > MAX_VALUE_LENGTH:
        return None
    
    # Strip leading/trailing whitespace
    value = value.strip()
    
    if not value:
        return None
    
    return value


def is_header_allowed(key: str) -> bool:
    """Check if a header is in the allowed list for forwarding."""
    key_lower = key.lower()
    return any(key_lower.startswith(prefix) or key_lower == prefix 
               for prefix in ALLOWED_HEADER_PREFIXES)


def build_grpc_metadata(
    http_headers: Dict[str, str],
    additional_metadata: Optional[Dict[str, str]] = None
) -> List[Tuple[str, str]]:
    """
    Build sanitized gRPC metadata from HTTP headers and additional metadata.
    
    This function:
    1. Filters headers against an allowlist
    2. Sanitizes keys and values to prevent injection
    3. Enforces limits on number of entries and value sizes
    4. Returns a list of (key, value) tuples safe for gRPC metadata
    
    Args:
        http_headers: Dictionary of HTTP headers from the incoming request
        additional_metadata: Optional additional metadata to include
        
    Returns:
        List of sanitized (key, value) tuples for gRPC metadata
        
    Raises:
        MetadataValidationError: If metadata construction fails critically
    """
    metadata = []
    seen_keys = set()
    
    if not isinstance(http_headers, dict):
        raise MetadataValidationError("http_headers must be a dictionary")
    
    # Process HTTP headers
    for raw_key, raw_value in http_headers.items():
        if len(metadata) >= MAX_METADATA_ENTRIES:
            break
        
        # Check if header is allowed for forwarding
        if not is_header_allowed(raw_key):
            continue
        
        # Sanitize key
        clean_key = sanitize_metadata_key(raw_key)
        if clean_key is None:
            continue
        
        # Prevent duplicate keys
        if clean_key in seen_keys:
            continue
        
        # Sanitize value
        clean_value = sanitize_metadata_value(raw_value, clean_key)
        if clean_value is None:
            continue
        
        metadata.append((clean_key, clean_value))
        seen_keys.add(clean_key)
    
    # Process additional metadata
    if additional_metadata and isinstance(additional_metadata, dict):
        for raw_key, raw_value in additional_metadata.items():
            if len(metadata) >= MAX_METADATA_ENTRIES:
                break
            
            clean_key = sanitize_metadata_key(raw_key)
            if clean_key is None:
                continue
            
            if clean_key in seen_keys:
                continue
            
            clean_value = sanitize_metadata_value(raw_value, clean_key)
            if clean_value is None:
                continue
            
            metadata.append((clean_key, clean_value))
            seen_keys.add(clean_key)
    
    return metadata


