class MetadataSanitizationInterceptor(grpc.ServerInterceptor):
    """
    Server interceptor that sanitizes incoming metadata before
    forwarding to backend services.
    """
    
    def intercept_service(self, continuation, handler_call_details):
        """Intercept and sanitize metadata on incoming calls."""
        # Extract and sanitize incoming metadata
        incoming_metadata = dict(handler_call_details.invocation_metadata)
        
        # Rebuild sanitized metadata
        sanitized = build_grpc_metadata(incoming_metadata)
        
        # Store sanitized metadata for use by handlers
        # In practice, you'd use contextvars or similar
        handler_call_details.invocation_metadata = sanitized
        
        return continuation(handler_call_details)


