class APIGatewayServicer:
    """
    Servicer that receives requests and forwards them to backend services.
    Demonstrates proper metadata handling with set_trailing_metadata.
    """
    
    def __init__(self, backend_clients: Dict[str, GatewayGRPCClient]):
        """
        Args:
            backend_clients: Map of service name to GatewayGRPCClient
        """
        self.backend_clients = backend_clients
    
    def ForwardRequest(self, request, context):
        """
        Generic request forwarding handler.
        
        This method:
        1. Extracts metadata from the incoming request
        2. Sanitizes it
        3. Forwards to the appropriate backend
        4. Sets trailing metadata on the response
        """
        # Extract incoming metadata
        incoming_metadata = dict(context.invocation_metadata())
        
        # Determine target service from metadata or request
        target_service = incoming_metadata.get("x-request-target-service", "")
        target_method = incoming_metadata.get("x-request-target-method", "")
        
        # Validate target service name (prevent injection in service routing)
        if not re.match(r'^[a-zA-Z][a-zA-Z0-9_.]{0,127}$', target_service):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Invalid target service name")
            return None
        
        if not re.match(r'^[a-zA-Z][a-zA-Z0-9_]{0,63}$', target_method):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details("Invalid target method name")
            return None
        
        # Get the appropriate backend client
        client = self.backend_clients.get(target_service)
        if not client:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"Service not found")
            return None
        
        # Build sanitized metadata for forwarding
        sanitized_metadata = build_grpc_metadata(
            incoming_metadata,
            additional_metadata={
                "x-request-gateway": "api-gateway-v1",
                "x-request-forwarded": "true",
            }
        )
        
        try:
            # Forward the request
            response_bytes, trailing_metadata, status_code = client.forward_unary_request(
                service_name=target_service,
                method_name=target_method,
                request_data=request.SerializeToString() if hasattr(request, 'SerializeToString') else request,
                http_headers=incoming_metadata,
                timeout=30.0
            )
            
            # Sanitize trailing metadata from backend before setting on response
            sanitized_trailing = []
            for key, value in trailing_metadata:
                clean_key = sanitize_metadata_key(key)
                if clean_key and not clean_key.startswith("grpc-"):
                    clean_value = sanitize_metadata_value(value, clean_key)
                    if clean_value is not None:
                        sanitized_trailing.append((clean_key, clean_value))
            
            # Set sanitized trailing metadata on the response context
            context.set_trailing_metadata(sanitized_trailing)
            
            if status_code != grpc.StatusCode.OK:
                context.set_code(status_code)
                return None
            
            return response_bytes
            
        except Exception as e:
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details("Internal gateway error")
            return None


