def create_gateway_server(
    listen_address: str = '[::]:50051',
    backend_services: Optional[Dict[str, str]] = None
) -> grpc.Server:
    """
    Create and configure the API gateway gRPC server.
    
    Args:
        listen_address: Address to listen on
        backend_services: Map of service name to backend address
    """
    # Create backend clients
    backend_clients = {}
    if backend_services:
        for service_name, address in backend_services.items():
            backend_clients[service_name] = GatewayGRPCClient(address)
    
    # Create server with sanitization interceptor
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        interceptors=[MetadataSanitizationInterceptor()]
    )
    
    # In production, you'd register your generated servicer here
    # e.g., gateway_pb2_grpc.add_GatewayServiceServicer_to_server(
    #     APIGatewayServicer(backend_clients), server
    # )
    
    server.add_insecure_port(listen_address)
    
    return server


